import { GoogleGenAI, Modality } from "@google/genai";
import { base64ToUint8Array, addWavHeader } from "../utils/audioUtils";

// Initialize the Google GenAI client exclusively with the environment variable.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Transcribes audio to text using Gemini 3 Flash.
 */
export const transcribeAudio = async (base64Audio: string, mimeType: string): Promise<string> => {
  try {
    // Using 'gemini-3-flash-preview' for the transcription task.
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Audio
            }
          },
          {
            text: "Hãy chuyển âm thanh này thành văn bản một cách chính xác. Chỉ trả về nội dung văn bản đã chép, không thêm bất kỳ lời bình nào."
          }
        ]
      }
    });

    return response.text || "Không thể tạo bản chép lời.";
  } catch (error) {
    console.error("Transcription error:", error);
    throw error;
  }
};

/**
 * Generates speech from text using Gemini 2.5 Flash TTS model.
 * Returns a Blob URL for the WAV file.
 */
export const generateSpeech = async (text: string, voiceName: string = 'Puck'): Promise<string> => {
  try {
    // Generate content with Modality.AUDIO and speechConfig.
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: voiceName },
          },
        },
      },
    });

    // Robust check for the audio data in candidates and parts.
    // The model might return multiple parts (e.g. text explanation + audio), 
    // so we search for the one containing inlineData.
    const candidate = response.candidates?.[0];
    if (!candidate) {
      throw new Error("Gemini không trả về kết quả nào (No candidates found).");
    }

    const audioPart = candidate.content?.parts?.find(part => part.inlineData);
    const base64Audio = audioPart?.inlineData?.data;

    if (!base64Audio) {
      console.error("Gemini Response Structure:", JSON.stringify(response, null, 2));
      throw new Error("Không nhận được dữ liệu âm thanh từ Gemini. Vui lòng thử lại với nội dung khác.");
    }

    // Decode the raw PCM bytes.
    const pcmData = base64ToUint8Array(base64Audio);

    // Wrap raw PCM in a WAV header (24kHz is default for gemini-2.5-flash-preview-tts).
    // Note: If you encounter distorted audio, ensure the sample rate matches the model output.
    const wavBuffer = addWavHeader(pcmData, 24000, 1, 16);

    const blob = new Blob([wavBuffer], { type: 'audio/wav' });
    return URL.createObjectURL(blob);

  } catch (error) {
    console.error("TTS error details:", error);
    throw error;
  }
};

/**
 * Analyzes a document (Image or PDF) and extracts content based on the target format.
 */
export const analyzeDocument = async (base64Data: string, mimeType: string, targetFormat: 'word' | 'excel' | 'ppt'): Promise<string> => {
  try {
    let prompt = "";

    if (targetFormat === 'excel') {
      prompt = "Bạn là chuyên gia nhập liệu. Chuyển đổi tài liệu/hình ảnh này thành định dạng HTML sạch phù hợp để dán vào Excel. Sử dụng cấu trúc <table>. QUAN TRỌNG: Giữ nguyên bố cục gốc, các ô gộp (rowspan/colspan), màu nền và kiểu viền càng giống càng tốt bằng CSS inline. KHÔNG bao gồm các khối mã markdown (như ```html), chỉ trả về mã HTML.";
    } else if (targetFormat === 'word') {
      prompt = "Bạn là chuyên gia phục hồi tài liệu. Tái tạo tài liệu này dưới dạng tệp HTML có độ trung thực cao phù hợp để mở trong Microsoft Word. QUAN TRỌNG: Giữ nguyên bố cục chính xác, kiểu phông chữ (đậm, nghiêng, tiêu đề), cấu trúc bảng, viền và màu nền bằng CSS inline. KHÔNG bao gồm các khối mã markdown (như ```html), chỉ trả về mã HTML bắt đầu bằng <html>.";
    } else {
      prompt = "Bạn là nhà thiết kế bản thuyết trình. Phân tích tài liệu này và tạo dàn ý chi tiết cho bài thuyết trình PowerPoint. Chia nội dung thành các Slide. Đối với mỗi slide, cung cấp Tiêu đề và các gạch đầu dòng nội dung. Sử dụng định dạng Markdown.";
    }

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview', 
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Data
            }
          },
          {
            text: prompt
          }
        ]
      }
    });

    let text = response.text || "";
    text = text.replace(/```html/g, "").replace(/```/g, "");

    return text;
  } catch (error) {
    console.error("Document analysis error:", error);
    throw error;
  }
};

