export const fetchNewsFeed = async (): Promise<any> => {
  try {
    const prompt = `Tổng hợp tin tức mới nhất về các chủ đề sau trong vòng 24h qua:
    1. Kinh tế & Tài chính thế giới/Việt Nam.
    2. Xu hướng thời trang thế giới.
    3. Ngành sản xuất GIÀY DA và TÚI XÁCH tại Việt Nam (thông tin xuất khẩu, nguyên liệu, nhà máy).
    Yêu cầu: Trả về dữ liệu dưới định dạng JSON với cấu trúc: 
    {
      "articles": [{ "title": "...", "summary": "...", "source": "...", "url": "...", "category": "...", "trend": "up/down/stable" }],
      "market_stats": [{ "label": "Chỉ số XYZ", "value": "...", "change": "..." }]
    }
    Lưu ý: Chỉ trả về JSON, không kèm văn bản khác.`;

    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
      }
    });

    const data = JSON.parse(response.text || "{}");
    return {
      data,
      sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (error) {
    console.error("News fetch error:", error);
    throw error;
  }
};

