import React, { useState, useEffect, useMemo } from 'react';
import { Volume2, Play, Download, Sparkles, AlertCircle, Quote, Languages, Info } from 'lucide-react';
import Button from './Button';
import { VOICE_OPTIONS, THEME_OPTIONS, LANGUAGES } from '../types';
import { generateSpeech } from '../services/geminiService';

const TextToAudio: React.FC = () => {
  const [text, setText] = useState('');
  const [selectedLanguage, setSelectedLanguage] = useState('vi');
  const [selectedVoice, setSelectedVoice] = useState('Puck');
  const [selectedTheme, setSelectedTheme] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    return () => { if (audioUrl) URL.revokeObjectURL(audioUrl); };
  }, [audioUrl]);

  // Filter voices by selected language
  const filteredVoices = useMemo(() => {
    return VOICE_OPTIONS.filter(v => v.languages.includes(selectedLanguage));
  }, [selectedLanguage]);

  // Set default voice when language changes
  useEffect(() => {
    const recommended = filteredVoices.find(v => v.recommendedFor.includes(selectedLanguage)) || filteredVoices[0];
    if (recommended) setSelectedVoice(recommended.name);
  }, [selectedLanguage, filteredVoices]);

  const handleGenerate = async () => {
    if (!text.trim()) return;
    setIsLoading(true);
    setError(null);
    setAudioUrl(null);
    try {
      const url = await generateSpeech(text, selectedVoice);
      setAudioUrl(url);
    } catch (err: any) {
      setError(err.message || "Không thể tạo âm thanh.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="max-w-7xl mx-auto animate-fade-in">
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Left: Editor */}
        <div className="lg:col-span-7 space-y-6">
          <div className="bg-white rounded-2xl shadow-sm border border-gray-200 focus-within:ring-2 focus-within:ring-primary-500 overflow-hidden">
            <div className="border-b border-gray-100 p-4 bg-gray-50 flex justify-between items-center">
              <label className="flex items-center gap-2 text-sm font-bold text-gray-700 uppercase tracking-wide">
                <Quote size={16} className="text-primary-500" />
                Văn bản cần đọc
              </label>
              <div className="flex gap-2">
                {LANGUAGES.map(lang => (
                  <button
                    key={lang.id}
                    onClick={() => setSelectedLanguage(lang.id)}
                    className={`px-3 py-1 rounded-full text-xs font-bold transition-all border ${
                      selectedLanguage === lang.id 
                        ? 'bg-primary-600 text-white border-primary-600' 
                        : 'bg-white text-gray-500 border-gray-200 hover:border-primary-300'
                    }`}
                  >
                    {lang.flag} {lang.label}
                  </button>
                ))}
              </div>
            </div>
            <textarea
              value={text}
              onChange={(e) => setText(e.target.value)}
              placeholder="Nhập nội dung... Gemini hỗ trợ đọc đa ngôn ngữ với ngữ điệu tự nhiên."
              className="w-full h-[450px] p-6 text-gray-800 border-0 focus:ring-0 resize-none text-lg leading-relaxed bg-white"
            />
          </div>
          <div className="flex justify-between items-center">
            <div className="text-xs text-gray-400 italic flex items-center gap-1">
              <Info size={14} /> Tự động tối ưu hóa phát âm theo ngôn ngữ {LANGUAGES.find(l => l.id === selectedLanguage)?.label}
            </div>
            <Button size="lg" onClick={handleGenerate} disabled={!text.trim() || isLoading} isLoading={isLoading} icon={<Sparkles size={20} />}>
              Tạo Âm Thanh
            </Button>
          </div>
          {error && <div className="bg-red-50 text-red-600 p-4 rounded-lg flex gap-3 border border-red-100"><AlertCircle size={18} /><p className="text-sm">{error}</p></div>}
        </div>

        {/* Right: Settings */}
        <div className="lg:col-span-5 space-y-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
            <h3 className="text-sm font-bold text-gray-800 mb-4 uppercase flex items-center gap-2">
              <Volume2 size={18} className="text-primary-600" />
              Danh sách Giọng đọc ({selectedLanguage.toUpperCase()})
            </h3>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 max-h-[500px] overflow-y-auto pr-2 custom-scrollbar">
              {filteredVoices.map((voice) => {
                const isBestForLang = voice.recommendedFor.includes(selectedLanguage);
                return (
                  <button
                    key={voice.name}
                    onClick={() => setSelectedVoice(voice.name)}
                    className={`group relative p-3 rounded-xl border text-left transition-all ${
                      selectedVoice === voice.name 
                        ? 'border-primary-500 bg-primary-50 ring-1 ring-primary-500' 
                        : 'border-gray-100 hover:border-gray-200 hover:bg-gray-50'
                    }`}
                  >
                    {isBestForLang && (
                      <span className="absolute -top-2 -right-1 bg-green-500 text-white text-[9px] font-bold px-1.5 py-0.5 rounded shadow-sm">Tốt nhất</span>
                    )}
                    <div className="flex justify-between items-center mb-1">
                      <span className="font-bold text-sm text-gray-800">{voice.name}</span>
                      <span className={`text-[10px] px-1.5 py-0.5 rounded-full ${voice.gender === 'Nam' ? 'bg-blue-100 text-blue-700' : 'bg-pink-100 text-pink-700'}`}>{voice.gender}</span>
                    </div>
                    <div className="text-[11px] text-gray-500 leading-tight line-clamp-2">{voice.description}</div>
                  </button>
                );
              })}
            </div>
          </div>

          {audioUrl && (
            <div className="bg-white p-6 rounded-2xl shadow-xl border-t-4 border-primary-500 animate-slide-up">
              <h3 className="text-xs font-bold text-gray-500 uppercase mb-4 tracking-widest">Trình phát Audio</h3>
