              <a href={audioUrl} download={`speech-${Date.now()}.wav`} className="flex items-center justify-center gap-2 w-full py-3 bg-gray-900 text-white rounded-xl text-sm font-bold hover:bg-black transition-all">
                <Download size={18} /> Tải xuống (WAV)
              </a>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default TextToAudio;

