import { GoogleGenAI, Modality, Type } from "@google/genai";
import { base64ToUint8Array, addWavHeader } from "../utils/audioUtils";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const transcribeAudio = async (base64Audio: string, mimeType: string): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [{ inlineData: { mimeType, data: base64Audio } }, { text: "Hãy chuyển âm thanh này thành văn bản một cách chính xác." }]
      }
    });
    return response.text || "Không thể tạo bản chép lời.";
  } catch (error) {
    console.error("Transcription error:", error);
    throw error;
  }
};

export const generateSpeech = async (text: string, voiceName: string = 'Puck'): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: { prebuiltVoiceConfig: { voiceName } },
        },
      },
    });
    const candidate = response.candidates?.[0];
    const audioPart = candidate?.content?.parts?.find(part => part.inlineData);
    const base64Audio = audioPart?.inlineData?.data;
    if (!base64Audio) throw new Error("Không nhận được dữ liệu âm thanh.");
    const pcmData = base64ToUint8Array(base64Audio);
    const wavBuffer = addWavHeader(pcmData, 24000, 1, 16);
    return URL.createObjectURL(new Blob([wavBuffer], { type: 'audio/wav' }));
  } catch (error) {
    console.error("TTS error:", error);
    throw error;
  }
};

export const fetchNewsFeed = async (): Promise<any> => {
  try {
    // Sử dụng flash-preview để tốc độ phản hồi cực nhanh
    const prompt = `BẠN LÀ BIÊN TẬP VIÊN TIN TỨC CAO CẤP. Hãy quét Google Search để tìm 5-7 tin tức MỚI NHẤT (trong 24h qua) về:
    1. Kinh tế & Tài chính (VN và Thế giới).
    2. Xu hướng thời trang quốc tế.
    3. Ngành sản xuất GIÀY DA và TÚI XÁCH Việt Nam (số liệu xuất khẩu, đơn hàng, nguyên liệu).

    YÊU CẦU QUAN TRỌNG: 
    - Mỗi tin tức phải có "url" dẫn TRỰC TIẾP ĐẾN BÀI VIẾT, không được dẫn về trang chủ của báo (ví dụ: dẫn đến vnexpress.net/tin-abc chứ không phải vnexpress.net).
    - Phân tích xu hướng (trend) là up, down hoặc stable.
    - Cung cấp 3-4 chỉ số thị trường (market_stats) thực tế hiện tại.

    Trả về JSON: 
    {
      "articles": [{ "title": "...", "summary": "...", "source": "...", "url": "...", "category": "...", "trend": "up/down/stable" }],
      "market_stats": [{ "label": "...", "value": "...", "change": "..." }]
    }`;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview", 
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
      }
    });

    const data = JSON.parse(response.text || "{}");
    return {
      data,
      sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (error) {
    console.error("News fetch error:", error);
    throw error;
  }
};

export const analyzeDocument = async (base64Data: string, mimeType: string, targetFormat: 'word' | 'excel' | 'ppt'): Promise<string> => {
  try {
    let prompt = targetFormat === 'excel' ? "Chuyển thành bảng HTML sạch cho Excel." : 
                 targetFormat === 'word' ? "Tái tạo HTML cho Word." : "Tạo dàn ý slide PPT.";
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: { parts: [{ inlineData: { mimeType, data: base64Data } }, { text: prompt }] }
    });
    return (response.text || "").replace(/```html/g, "").replace(/```/g, "");
  } catch (error) {
    throw error;
  }
};

