import React, { useState } from 'react';
import { Upload, FileAudio, Copy, Check, AlertCircle, Mic2, Sparkles, Wand2 } from 'lucide-react';
import AudioRecorder from './AudioRecorder';
import Button from './Button';
import { transcribeAudio } from '../services/geminiService';
import { blobToBase64 } from '../utils/audioUtils';

const AudioToText: React.FC = () => {
  const [file, setFile] = useState<File | null>(null);
  const [recordedBlob, setRecordedBlob] = useState<Blob | null>(null);
  const [transcript, setTranscript] = useState<string>('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
      setRecordedBlob(null);
      setTranscript('');
      setError(null);
    }
  };

  const handleRecordingComplete = (blob: Blob) => {
    setRecordedBlob(blob);
    setFile(null);
    setTranscript('');
    setError(null);
  };

  const handleTranscribe = async () => {
    const audioSource = file || recordedBlob;
    if (!audioSource) return;

    setIsLoading(true);
    setError(null);
    setTranscript('');

    try {
      const base64 = await blobToBase64(audioSource);
      const mimeType = file ? file.type : 'audio/webm';
      const result = await transcribeAudio(base64, mimeType);
      setTranscript(result);
    } catch (err: any) {
      setError(err.message || "Lỗi xử lý âm thanh.");
    } finally {
      setIsLoading(false);
    }
  };

  const copyToClipboard = () => {
    if (transcript) {
      navigator.clipboard.writeText(transcript);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  const activeSource = file || recordedBlob;

  return (
    <div className="max-w-6xl mx-auto space-y-8 animate-fade-in pb-10">

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* Upload Card */}
        <div className={`group bg-white/80 backdrop-blur-xl p-8 rounded-[2.5rem] shadow-xl border border-white/60 transition-all duration-500 hover:shadow-2xl ${file ? 'ring-2 ring-indigo-500 bg-white' : ''}`}>
          <div className="flex items-center gap-3 mb-6">
            <div className="w-10 h-10 rounded-2xl bg-indigo-100 flex items-center justify-center text-indigo-600">
              <Upload size={20} />
            </div>
            <h3 className="text-lg font-black text-gray-900 tracking-tight uppercase tracking-wider">Tải lên âm thanh</h3>
          </div>

          <div className="relative">
            <input type="file" accept="audio/*" onChange={handleFileChange} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10" />
            <div className={`border-2 border-dashed rounded-3xl p-8 text-center transition-all duration-300 h-48 flex flex-col items-center justify-center ${file ? 'border-indigo-400 bg-indigo-50/50' : 'border-gray-200 hover:border-indigo-300 hover:bg-gray-50/50'}`}>
              {file ? (
                 <div className="text-indigo-600 font-bold flex flex-col items-center animate-scale-in">
                   <div className="w-16 h-16 rounded-2xl bg-white shadow-sm flex items-center justify-center mb-3">
                     <FileAudio size={32} />
                   </div>
                   <span className="truncate max-w-[200px] text-sm">{file.name}</span>
                   <span className="text-[10px] text-gray-400 mt-1 uppercase">{(file.size / 1024 / 1024).toFixed(2)} MB</span>
                 </div>
              ) : (
                <div className="space-y-3">
                  <p className="text-sm text-gray-600 font-bold">Kéo thả hoặc nhấn để chọn</p>
                  <p className="text-xs text-gray-400 font-medium">MP3, WAV, AAC, M4A...</p>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Recording Card */}
        <div className={`group bg-white/80 backdrop-blur-xl p-8 rounded-[2.5rem] shadow-xl border border-white/60 transition-all duration-500 hover:shadow-2xl ${recordedBlob ? 'ring-2 ring-indigo-500 bg-white' : ''}`}>
          <div className="flex items-center gap-3 mb-6">
            <div className="w-10 h-10 rounded-2xl bg-red-100 flex items-center justify-center text-red-600">
              <Mic2 size={20} />
            </div>
            <h3 className="text-lg font-black text-gray-900 tracking-tight uppercase tracking-wider">Ghi âm trực tiếp</h3>
          </div>
          <div className="h-48 flex flex-col justify-center">
            <AudioRecorder onRecordingComplete={handleRecordingComplete} />
          </div>
        </div>
      </div>

      {/* Action Button */}
      <div className="flex flex-col items-center justify-center py-6">
        <Button 
          size="lg" 
          onClick={handleTranscribe} 
          disabled={!activeSource || isLoading}
          className="w-full md:w-auto min-w-[320px] h-16 rounded-2xl text-xl font-black shadow-2xl shadow-indigo-200 bg-indigo-600 hover:bg-indigo-700 transition-all hover:scale-[1.02] active:scale-[0.98]"
          isLoading={isLoading}
        >
          {isLoading ? 'Đang phân tích...' : 'CHUYỂN THÀNH VĂN BẢN'}
        </Button>
      </div>

      {/* Transcript Result */}
      {transcript && (
        <div className="bg-white rounded-[2.5rem] shadow-2xl border border-gray-100 overflow-hidden animate-slide-up ring-1 ring-black/5">
          <div className="bg-gray-50/50 px-8 py-5 border-b border-gray-100 flex justify-between items-center backdrop-blur-sm">
            <h3 className="font-black text-gray-900 uppercase tracking-widest text-sm flex items-center gap-2">
              <Wand2 size={16} className="text-indigo-600" />
              Bản chép lời AI
            </h3>
            <button 
              onClick={copyToClipboard}
              className={`px-4 py-2 rounded-xl transition-all flex items-center gap-2 text-xs font-bold ${
                copied ? 'bg-green-100 text-green-700' : 'bg-white text-indigo-600 border border-indigo-100 hover:bg-indigo-50 shadow-sm'
              }`}
            >
              {copied ? <Check size={14} /> : <Copy size={14} />}
              {copied ? 'ĐÃ SAO CHÉP' : 'SAO CHÉP'}
            </button>
          </div>
          <div className="p-8">
            <textarea 
              readOnly 
              value={transcript} 
              className="w-full h-80 p-0 border-0 focus:ring-0 text-gray-800 leading-relaxed resize-none bg-transparent text-lg font-medium placeholder-gray-300"
              placeholder="Văn bản chép lời sẽ xuất hiện tại đây..."
            />
          </div>
        </div>
      )}

      {error && (
        <div className="bg-red-50 text-red-600 p-5 rounded-2xl flex items-start gap-4 border border-red-100 animate-shake">
          <AlertCircle className="shrink-0 mt-0.5" size={20} />
          <p className="text-sm font-bold">{error}</p>
        </div>
      )}
    </div>
  );
};

