export const fetchNewsFeed = async (): Promise<any> => {
  try {
    const prompt = `Tổng hợp bản tin thị trường giày da, túi xách và kinh tế Việt Nam mới nhất ngày hôm nay. 
    Vui lòng cung cấp danh sách các bài báo quan trọng và các chỉ số thị trường chính.
    Trả về dữ liệu dưới định dạng JSON với cấu trúc:
    {
      "articles": [
        {
          "title": "tiêu đề",
          "summary": "tóm tắt",
          "source": "nguồn",
          "url": "đường dẫn",
          "category": "lĩnh vực",
          "trend": "up/down/stable"
        }
      ],
      "market_stats": [
        { "label": "chỉ số", "value": "giá trị", "change": "biến động" }
      ]
    }`;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    let data = { articles: [], market_stats: [] };
    const text = response.text || "";
    const jsonMatch = text.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      try {
        data = JSON.parse(jsonMatch[0]);
      } catch (e) {
        console.error("Failed to parse market news JSON", e);
      }
    }

    return {
      data,
      // Extracted URLs from groundingChunks as required.
      sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (error) {
    console.error("Fetch news error:", error);
    throw error;
  }
};

