                    key={lang.id}
                    onClick={() => setSelectedLanguage(lang.id)}
                    className={`px-4 py-1.5 rounded-xl text-xs font-bold transition-all ${
                      selectedLanguage === lang.id 
                        ? 'bg-indigo-600 text-white shadow-lg' 
                        : 'text-gray-500 hover:text-indigo-600'
