import React, { useState, useRef, useEffect } from 'react';
import { Mic, Square, RefreshCcw } from 'lucide-react';
import Button from './Button';

interface AudioRecorderProps {
  onRecordingComplete: (blob: Blob) => void;
  disabled?: boolean;
}

const AudioRecorder: React.FC<AudioRecorderProps> = ({ onRecordingComplete, disabled }) => {
  const [isRecording, setIsRecording] = useState(false);
  const [recordingTime, setRecordingTime] = useState(0);
  const [audioURL, setAudioURL] = useState<string | null>(null);

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);
  const timerRef = useRef<number | null>(null);

  useEffect(() => {
    return () => {
      if (timerRef.current) window.clearInterval(timerRef.current);
      if (audioURL) URL.revokeObjectURL(audioURL);
    };
  }, [audioURL]);

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];

      mediaRecorder.ondataavailable = (e) => {
        if (e.data.size > 0) chunksRef.current.push(e.data);
      };

      mediaRecorder.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: 'audio/webm' });
        const url = URL.createObjectURL(blob);
        setAudioURL(url);
        onRecordingComplete(blob);
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
      setRecordingTime(0);

      timerRef.current = window.setInterval(() => {
        setRecordingTime(prev => prev + 1);
      }, 1000);

    } catch (err) {
      console.error("Error accessing microphone:", err);
      alert("Không thể truy cập microphone.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      if (timerRef.current) {
        window.clearInterval(timerRef.current);
        timerRef.current = null;
      }
    }
  };

  const resetRecording = () => {
    setAudioURL(null);
    setRecordingTime(0);
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  if (audioURL) {
    return (
      <div className="flex flex-col items-center gap-6 p-8 bg-gray-50/50 rounded-[2rem] border border-gray-100 w-full shadow-inner animate-scale-in">
        <audio src={audioURL} controls className="w-full h-12 invert brightness-0" />
        <Button variant="secondary" onClick={resetRecording} size="sm" className="rounded-2xl px-6 py-3 font-black text-[10px] uppercase tracking-widest text-gray-500 hover:text-green-600 transition-colors" icon={<RefreshCcw size={14}/>}>
          Ghi âm lại
        </Button>
      </div>
    );
  }

  return (
    <div className="flex flex-col items-center justify-center p-10 h-full">
       {isRecording ? (
         <div className="text-center animate-scale-in">
            <div className="flex items-center justify-center gap-2 mb-6">
              <span className="w-3 h-3 bg-red-600 rounded-full animate-pulse shadow-lg shadow-red-200"></span>
              <div className="text-4xl font-extrabold text-gray-900 font-mono tracking-tighter">
                {formatTime(recordingTime)}
              </div>
            </div>
            <Button variant="danger" onClick={stopRecording} className="h-16 px-10 rounded-3xl shadow-2xl shadow-red-200 font-black text-sm uppercase tracking-widest bg-red-600 hover:bg-red-700 text-white" icon={<Square size={20} />}>
              DỪNG GHI
            </Button>
         </div>
       ) : (
         <div className="text-center animate-scale-in">
           <button 
             onClick={startRecording} 
             disabled={disabled}
             className="w-24 h-24 rounded-full bg-white border-4 border-green-50 flex items-center justify-center text-green-600 shadow-2xl shadow-green-200 transition-all hover:scale-110 active:scale-90 group relative"
           >
             <div className="absolute inset-0 bg-green-500/10 rounded-full scale-110 group-hover:scale-125 transition-transform duration-500"></div>
             <Mic size={40} className="relative z-10" />
           </button>
           <p className="mt-8 text-xs font-black text-gray-400 uppercase tracking-[0.2em]">Nhấn để bắt đầu ghi âm</p>
         </div>
       )}
    </div>
  );
};

export default AudioRecorder;

