        </div>

        <div className="mica p-10 rounded-[3rem] shadow-2xl border border-white/50 flex flex-col">
          <h3 className="text-lg font-black text-gray-900 mb-8 flex items-center gap-4 uppercase">
            <div className="w-10 h-10 rounded-xl bg-green-50 flex items-center justify-center text-green-600">
