import React, { useState, useRef, useEffect } from 'react';
import { MonitorPlay, Square, Download, FileText, AlertCircle, Video, Check, Copy, Sparkles, Wand2 } from 'lucide-react';
import Button from './Button';
import { transcribeAudio } from '../services/geminiService';
import { blobToBase64 } from '../utils/audioUtils';
import { UILang, TRANSLATIONS } from '../types';

interface Props { lang: UILang }

const ScreenRecorder: React.FC<Props> = ({ lang }) => {
  const [isRecording, setIsRecording] = useState(false);
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [recordingBlob, setRecordingBlob] = useState<Blob | null>(null);
  const [transcript, setTranscript] = useState<string>('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [recordingTime, setRecordingTime] = useState(0);
  const [copied, setCopied] = useState(false);

  const t = TRANSLATIONS[lang];
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);
  const timerRef = useRef<number | null>(null);
  const streamRef = useRef<MediaStream | null>(null);

  useEffect(() => {
    return () => {
      if (timerRef.current) window.clearInterval(timerRef.current);
      if (videoUrl) URL.revokeObjectURL(videoUrl);
      if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
    };
  }, [videoUrl]);

  const startRecording = async () => {
    try {
      setError(null);
      setTranscript('');
      const stream = await navigator.mediaDevices.getDisplayMedia({
        video: { frameRate: { ideal: 30 } },
        audio: { echoCancellation: true, noiseSuppression: true }
      });
      streamRef.current = stream;
      const mediaRecorder = new MediaRecorder(stream, { mimeType: 'video/webm' });
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];
      mediaRecorder.ondataavailable = (e) => { if (e.data.size > 0) chunksRef.current.push(e.data); };
      mediaRecorder.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: 'video/webm' });
        setVideoUrl(URL.createObjectURL(blob));
        setRecordingBlob(blob);
      };
      mediaRecorder.start();
      setIsRecording(true);
      setRecordingTime(0);
      timerRef.current = window.setInterval(() => setRecordingTime(prev => prev + 1), 1000);
    } catch (err: any) {
      if (err.name !== 'NotAllowedError') setError("Cần cấp quyền quay màn hình.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      if (timerRef.current) { window.clearInterval(timerRef.current); timerRef.current = null; }
      if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
    }
  };

  const handleTranscribeMeeting = async () => {
    if (!recordingBlob) return;
    setIsLoading(true);
    setError(null);
    try {
      const base64 = await blobToBase64(recordingBlob);
      const result = await transcribeAudio(base64, 'video/webm');
      setTranscript(result);
    } catch (err: any) {
      setError("Lỗi xử lý: " + err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="max-w-7xl mx-auto space-y-12 animate-slide-up">
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
        <div className="lg:col-span-4 space-y-8">
          <div className="bg-white/95 mica p-10 rounded-[3rem] shadow-2xl border border-white/50 ring-1 ring-black/5">
            <h3 className="text-xs font-black text-gray-400 uppercase tracking-[0.3em] mb-8 flex items-center gap-3">
              <Video size={20} className="text-green-600" />
              RECORDING DOCK
            </h3>
            {!isRecording && !videoUrl && (
              <div className="space-y-6">
                <div className="p-6 bg-green-50 rounded-3xl border border-green-100 text-green-700 text-xs font-bold leading-relaxed">
                  💡 Nhớ chọn <b>"Chia sẻ âm thanh"</b> khi chọn thẻ trình duyệt để AI có thể chép lời cuộc họp.
                </div>
                <Button onClick={startRecording} className="w-full h-16 rounded-3xl bg-green-600 text-white font-black text-sm uppercase shadow-2xl shadow-green-200" icon={<MonitorPlay size={20} />}>
                  {t.labels.startBtn.split(' ')[0]} Màn hình
                </Button>
              </div>
            )}
            {isRecording && (
              <div className="text-center space-y-8 animate-pulse">
                <div className="text-6xl font-black text-red-600 tracking-tighter font-mono">{formatTime(recordingTime)}</div>
                <Button variant="danger" onClick={stopRecording} className="w-full h-16 rounded-3xl bg-red-600 text-white font-black text-sm uppercase" icon={<Square size={20} />}>
                  DỪNG & LƯU
                </Button>
              </div>
            )}
            {videoUrl && !isRecording && (
              <div className="space-y-4">
                <Button onClick={() => { setVideoUrl(null); setTranscript(''); }} variant="secondary" className="w-full h-14 rounded-2xl font-black text-xs uppercase text-gray-400">Ghi lại mới</Button>
                <a href={videoUrl} download="VPTX_Meeting.webm" className="flex items-center justify-center gap-3 w-full h-16 bg-gray-900 text-white rounded-3xl font-black text-sm uppercase shadow-2xl">
                  <Download size={20} /> {t.labels.downloadBtn} VIDEO
                </a>
              </div>
            )}
          </div>
          {videoUrl && !isRecording && (
            <div className="mica p-10 rounded-[3rem] shadow-2xl border border-white/50 text-center space-y-6">
               <div className="w-16 h-16 bg-green-50 rounded-full flex items-center justify-center mx-auto text-green-600"><Sparkles size={32} /></div>
               <div>
                  <h4 className="font-black text-gray-900 uppercase text-xs tracking-widest mb-2">Trí tuệ nhân tạo</h4>
                  <p className="text-[10px] text-gray-400 font-bold leading-relaxed px-4">AI Gemini sẽ quét nội dung âm thanh của video và tạo bản tóm tắt tự động cho bạn.</p>
               </div>
               <Button onClick={handleTranscribeMeeting} disabled={isLoading} isLoading={isLoading} className="w-full h-14 rounded-2xl bg-green-600 text-white font-black text-xs uppercase shadow-xl shadow-green-200" icon={<Wand2 size={18} />}>
                  PHÂN TÍCH CUỘC HỌP
               </Button>
            </div>
          )}
        </div>

        <div className="lg:col-span-8 space-y-10">
          {videoUrl ? (
            <div className="bg-black rounded-[4rem] overflow-hidden shadow-2xl border-4 border-white/20 aspect-video ring-1 ring-black/10">
              <video src={videoUrl} controls className="w-full h-full" />
            </div>
          ) : (
            <div className="bg-white/40 border-4 border-dashed border-gray-200 rounded-[4rem] h-96 flex flex-col items-center justify-center text-gray-300">
              <MonitorPlay size={64} className="mb-6 opacity-20" />
              <p className="font-black text-xs uppercase tracking-[0.3em] opacity-40 italic">Waiting for recording...</p>
            </div>
          )}

          {transcript && (
            <div className="bg-white rounded-[3.5rem] shadow-2xl border border-gray-100 overflow-hidden animate-slide-up">
              <div className="bg-gray-50/50 px-10 py-8 border-b border-gray-100 flex justify-between items-center">
                <h3 className="font-black text-gray-900 uppercase text-xs tracking-widest flex items-center gap-3">
                   <FileText size={18} className="text-green-600" /> Transcribed Content
                </h3>
                <button onClick={() => { navigator.clipboard.writeText(transcript); setCopied(true); setTimeout(() => setCopied(false), 2000); }} className="text-green-600 font-black text-xs hover:underline uppercase tracking-widest">{copied ? 'ĐÃ CHÉP' : 'SAO CHÉP'}</button>
              </div>
              <div className="p-10">
                <div className="text-gray-700 text-xl font-medium leading-relaxed whitespace-pre-wrap max-h-[500px] overflow-y-auto custom-scrollbar">{transcript}</div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

