import React, { useState } from 'react';
import { Upload, FileAudio, Copy, Check, AlertCircle, Mic2, Sparkles, Wand2 } from 'lucide-react';
import AudioRecorder from './AudioRecorder';
import Button from './Button';
import { transcribeAudio } from '../services/geminiService';
import { blobToBase64 } from '../utils/audioUtils';
import { UILang, TRANSLATIONS } from '../types';

interface Props { lang: UILang }

const AudioToText: React.FC<Props> = ({ lang }) => {
  const [file, setFile] = useState<File | null>(null);
  const [recordedBlob, setRecordedBlob] = useState<Blob | null>(null);
  const [transcript, setTranscript] = useState<string>('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  const t = TRANSLATIONS[lang];

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
      setRecordedBlob(null);
      setTranscript('');
      setError(null);
    }
  };

  const handleRecordingComplete = (blob: Blob) => {
    setRecordedBlob(blob);
    setFile(null);
    setTranscript('');
    setError(null);
  };

  const handleTranscribe = async () => {
    const audioSource = file || recordedBlob;
    if (!audioSource) return;

    setIsLoading(true);
    setError(null);
    setTranscript('');

    try {
      const base64 = await blobToBase64(audioSource);
      const mimeType = file ? file.type : 'audio/webm';
      const result = await transcribeAudio(base64, mimeType);
      setTranscript(result);
    } catch (err: any) {
      setError(err.message || "Lỗi xử lý âm thanh.");
    } finally {
      setIsLoading(false);
    }
  };

  const copyToClipboard = () => {
    if (transcript) {
      navigator.clipboard.writeText(transcript);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  const activeSource = file || recordedBlob;

  return (
    <div className="space-y-12 animate-fade-in max-w-screen-xl mx-auto">
      <div className="grid grid-cols-1 xl:grid-cols-2 gap-12">
        {/* Input Column */}
        <div className="space-y-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
            <div className={`card-premium p-8 rounded-3xl ${file ? 'ring-2 ring-green-500' : ''}`}>
              <div className="flex items-center gap-3 mb-6">
                <Upload size={20} className="text-green-600" />
                <h3 className="font-bold text-gray-900 uppercase text-xs tracking-wider">Tải lên file</h3>
              </div>
              <label className="relative block h-40 border-2 border-dashed border-gray-200 rounded-2xl hover:bg-green-50/30 hover:border-green-300 transition-all cursor-pointer">
                <input type="file" accept="audio/*" onChange={handleFileChange} className="sr-only" />
                <div className="flex flex-col items-center justify-center h-full text-center p-4">
                  {file ? (
                    <div className="flex flex-col items-center animate-fade-in">
                      <FileAudio size={32} className="text-green-600 mb-2" />
                      <span className="text-xs font-bold text-gray-700 truncate max-w-[150px]">{file.name}</span>
                    </div>
                  ) : (
                    <>
                      <FileAudio size={24} className="text-gray-300 mb-2" />
                      <span className="text-[11px] font-bold text-gray-400 uppercase leading-relaxed">{t.labels.uploadArea}</span>
                    </>
                  )}
                </div>
              </label>
            </div>

            <div className={`card-premium p-8 rounded-3xl ${recordedBlob ? 'ring-2 ring-green-500' : ''}`}>
              <div className="flex items-center gap-3 mb-6">
                <Mic2 size={20} className="text-red-600" />
                <h3 className="font-bold text-gray-900 uppercase text-xs tracking-wider">Ghi âm trực tiếp</h3>
              </div>
              <AudioRecorder onRecordingComplete={handleRecordingComplete} />
            </div>
          </div>

          <Button 
            size="lg" 
            onClick={handleTranscribe} 
            disabled={!activeSource || isLoading}
            className="w-full h-16 rounded-2xl text-lg font-black bg-green-600 hover:bg-green-700 shadow-xl shadow-green-100"
            isLoading={isLoading}
            icon={!isLoading && <Sparkles size={20} />}
          >
            {isLoading ? 'ĐANG PHÂN TÍCH...' : t.labels.startBtn.toUpperCase()}
          </Button>

          {error && (
            <div className="bg-red-50 text-red-600 p-6 rounded-2xl flex items-center gap-4 border border-red-100 animate-fade-in">
              <AlertCircle size={20} />
              <p className="text-sm font-bold">{error}</p>
            </div>
          )}
        </div>

        {/* Output Column */}
        <div className="card-premium rounded-3xl overflow-hidden flex flex-col h-[550px]">
          <div className="bg-gray-50 px-8 py-5 border-b border-gray-200 flex justify-between items-center">
            <h3 className="font-black text-gray-900 uppercase tracking-widest text-[11px] flex items-center gap-2">
              <Wand2 size={16} className="text-green-600" />
              Kết quả AI Transcription
            </h3>
            {transcript && (
              <button 
                onClick={copyToClipboard}
                className={`px-4 py-2 rounded-xl transition-all flex items-center gap-2 text-xs font-bold ${
                  copied ? 'bg-green-600 text-white shadow-lg' : 'bg-white text-green-700 border border-green-200 hover:bg-green-50'
                }`}
              >
                {copied ? <Check size={14} /> : <Copy size={14} />}
                {copied ? 'ĐÃ CHÉP' : t.labels.copyBtn.toUpperCase()}
              </button>
            )}
          </div>
          <div className="p-8 flex-grow">
            <textarea 
              readOnly 
              value={transcript} 
              className="w-full h-full p-0 border-0 focus:ring-0 text-gray-800 leading-relaxed resize-none bg-transparent text-lg md:text-xl font-medium placeholder-gray-300"
              placeholder="Văn bản chép lời sẽ hiển thị tại đây sau khi phân tích..."
            />
          </div>
        </div>
      </div>
    </div>
  );
};

export default AudioToText;

import React, { useState, useEffect, useMemo } from 'react';
import { Volume2, Download, Sparkles, AlertCircle, Quote, Info, Headphones, Check } from 'lucide-react';
import Button from './Button';
import { VOICE_OPTIONS, LANGUAGES, UILang, TRANSLATIONS } from '../types';
import { generateSpeech } from '../services/geminiService';

interface Props { lang: UILang }

const TextToAudio: React.FC<Props> = ({ lang }) => {
  const [text, setText] = useState('');
  const [selectedLanguage, setSelectedLanguage] = useState('vi');
  const [selectedVoice, setSelectedVoice] = useState('Puck');
  const [isLoading, setIsLoading] = useState(false);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const t = TRANSLATIONS[lang];

  useEffect(() => {
    return () => { if (audioUrl) URL.revokeObjectURL(audioUrl); };
  }, [audioUrl]);

  const filteredVoices = useMemo(() => {
    return VOICE_OPTIONS.filter(v => v.languages.includes(selectedLanguage));
  }, [selectedLanguage]);

  useEffect(() => {
    const recommended = filteredVoices.find(v => v.recommendedFor.includes(selectedLanguage)) || filteredVoices[0];
    if (recommended) setSelectedVoice(recommended.name);
  }, [selectedLanguage, filteredVoices]);

  const handleGenerate = async () => {
    if (!text.trim()) return;
    setIsLoading(true);
    setError(null);
    setAudioUrl(null);
    try {
      const url = await generateSpeech(text, selectedVoice);
      setAudioUrl(url);
    } catch (err: any) {
      setError(err.message || "Không thể tạo âm thanh.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="max-w-screen-xl mx-auto space-y-12 animate-fade-in">
      <div className="grid grid-cols-1 xl:grid-cols-12 gap-12 items-start">

        {/* Editor Area */}
