                <Quote size={16} className="text-green-600" />
                Nội dung văn bản
              </label>
              <div className="flex bg-gray-50 p-1 rounded-2xl border border-gray-100">
                {LANGUAGES.map(l => (
                  <button
                    key={l.id}
                    onClick={() => setSelectedLanguage(l.id)}
                    className={`px-5 py-2 rounded-xl text-xs font-bold transition-all ${
                      selectedLanguage === l.id 
                        ? 'bg-green-600 text-white shadow-lg shadow-green-100' 
                        : 'text-gray-500 hover:text-green-700'
                    }`}
                  >
                    {l.flag} {l.label}
                  </button>
                ))}
              </div>
            </div>

            <textarea
              value={text}
              onChange={(e) => setText(e.target.value)}
              placeholder="Nhập nội dung cần chuyển đổi thành giọng nói tại đây..."
              className="w-full h-[450px] p-10 text-gray-800 border-0 focus:ring-0 resize-none text-xl md:text-2xl font-medium leading-relaxed bg-white placeholder-gray-300"
            />

            <div className="p-8 bg-gray-50 border-t border-gray-100 flex items-center justify-between">
              <div className="flex items-center gap-3 text-[10px] text-gray-400 font-bold uppercase tracking-widest">
                <Info size={16} className="text-green-500" />
                Gemini AI Voice Engine
              </div>
              <Button 
                size="lg" 
                onClick={handleGenerate} 
                disabled={!text.trim() || isLoading} 
                isLoading={isLoading}
                className="rounded-2xl px-10 h-16 text-lg font-black bg-green-600 hover:bg-green-700 shadow-xl shadow-green-100"
                icon={!isLoading && <Sparkles size={20} />}
              >
                {t.labels.startBtn}
              </Button>
            </div>
          </div>
          {error && (
            <div className="bg-red-50 text-red-600 p-6 rounded-2xl flex items-center gap-4 border border-red-100 animate-fade-in">
              <AlertCircle size={20} />
              <p className="text-sm font-bold uppercase">{error}</p>
            </div>
          )}
        </div>

        {/* Control Area */}
        <div className="xl:col-span-4 space-y-8">
          <div className="card-premium p-8 rounded-3xl">
            <h3 className="text-[11px] font-black text-gray-400 uppercase tracking-widest mb-8 flex items-center gap-3">
              <Headphones size={18} className="text-green-600" />
