                  >
                    <div className="flex justify-between items-center mb-2">
                      <div className="flex items-center gap-2">
                        <span className={`font-bold text-sm ${isActive ? 'text-green-700' : 'text-gray-900'}`}>{voice.name}</span>
                        {isActive && <Check size={14} className="text-green-600" />}
                      </div>
                      <span className={`text-[9px] font-black px-2 py-0.5 rounded-full ${voice.gender === 'Nam' ? 'bg-blue-100 text-blue-600' : 'bg-pink-100 text-pink-600'}`}>
                        {voice.gender.toUpperCase()}
                      </span>
                    </div>
                    <p className="text-[11px] text-gray-500 leading-relaxed italic">{voice.description}</p>
                  </button>
                );
              })}
            </div>
          </div>

          {audioUrl && (
