                <div className="flex flex-col items-center justify-center h-full text-center p-8">
                  {file ? (
                    <div className="flex flex-col items-center animate-fade-in">
                      <FileAudio size={56} className="text-primary-900 mb-4" />
                      <span className="text-base font-black text-gray-900 truncate max-w-[180px]">{file.name}</span>
                    </div>
                  ) : (
                    <>
                      <FileAudio size={40} className="text-gray-300 mb-4" />
                      <span className="text-sm font-black text-gray-400 uppercase leading-relaxed text-center px-6">{t.labels.uploadArea}</span>
                    </>
                  )}
                </div>
              </label>
            </div>

            <div className={`card-premium p-10 rounded-3xl ${recordedBlob ? 'ring-4 ring-primary-900 shadow-2xl shadow-primary-900/10' : ''}`}>
              <div className="flex items-center gap-4 mb-8">
                <Mic2 size={28} className="text-red-700" />
                <h3 className="font-black text-gray-900 uppercase text-lg tracking-widest">{t.labels.recordLive}</h3>
              </div>
              <AudioRecorder onRecordingComplete={handleRecordingComplete} lang={lang} />
            </div>
          </div>

          <button 
            onClick={handleTranscribe} 
            disabled={!activeSource || isLoading}
            className={`w-full h-24 rounded-[2rem] text-2xl font-black shadow-2xl transition-all active:scale-95 flex items-center justify-center gap-6 ${
              !activeSource || isLoading 
                ? 'bg-gray-200 text-gray-400 cursor-not-allowed shadow-none' 
                : 'bg-primary-900 text-white hover:bg-primary-800 shadow-primary-900/20'
            }`}
