        </div>

        {/* Transcription Output Area */}
        <div className="card-premium rounded-[3rem] overflow-hidden flex flex-col h-[700px] shadow-2xl">
          <div className="bg-gray-50 px-12 py-8 border-b border-gray-200 flex justify-between items-center">
            <h3 className="font-black text-gray-900 uppercase tracking-widest text-sm flex items-center gap-4">
              <Wand2 size={24} className="text-primary-900" />
              {t.labels.transcriptionResult}
            </h3>
            {transcript && (
              <button 
                onClick={copyToClipboard}
                className={`px-8 py-3 rounded-2xl transition-all flex items-center gap-3 text-sm font-black shadow-lg ${
                  copied ? 'bg-primary-900 text-white' : 'bg-white text-primary-900 border border-primary-200 hover:bg-primary-50'
                }`}
              >
                {copied ? <Check size={20} /> : <Copy size={20} />}
                {copied ? 'COPIED' : t.labels.copyBtn.toUpperCase()}
              </button>
            )}
