          <div className="p-12 flex-grow">
            <textarea 
              readOnly 
              value={transcript} 
              className="w-full h-full p-0 border-0 focus:ring-0 text-gray-900 leading-relaxed resize-none bg-transparent text-2xl md:text-3xl font-medium placeholder-gray-300 custom-scrollbar"
              placeholder={t.labels.placeholderSTT}
            />
          </div>
        </div>
      </div>
    </div>
  );
};

