export default TextToAudio;

import React, { useState, useRef, useEffect } from 'react';
import { MonitorPlay, Square, Download, FileText, AlertCircle, Video, Check, Copy, Sparkles, Wand2 } from 'lucide-react';
import Button from './Button';
import { transcribeAudio } from '../services/geminiService';
import { blobToBase64 } from '../utils/audioUtils';
import { UILang, TRANSLATIONS } from '../types';

interface Props { lang: UILang }

const ScreenRecorder: React.FC<Props> = ({ lang }) => {
  const [isRecording, setIsRecording] = useState(false);
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [recordingBlob, setRecordingBlob] = useState<Blob | null>(null);
  const [transcript, setTranscript] = useState<string>('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [recordingTime, setRecordingTime] = useState(0);
  const [copied, setCopied] = useState(false);

  const t = TRANSLATIONS[lang];
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);
  const timerRef = useRef<number | null>(null);
  const streamRef = useRef<MediaStream | null>(null);

  useEffect(() => {
    return () => {
      if (timerRef.current) window.clearInterval(timerRef.current);
      if (videoUrl) URL.revokeObjectURL(videoUrl);
      if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
    };
  }, [videoUrl]);

  const startRecording = async () => {
    try {
      setError(null);
      setTranscript('');
      const stream = await navigator.mediaDevices.getDisplayMedia({
        video: { frameRate: { ideal: 30 } },
        audio: { echoCancellation: true, noiseSuppression: true }
      });
      streamRef.current = stream;
      const mediaRecorder = new MediaRecorder(stream, { mimeType: 'video/webm' });
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];
      mediaRecorder.ondataavailable = (e) => { if (e.data.size > 0) chunksRef.current.push(e.data); };
      mediaRecorder.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: 'video/webm' });
        setVideoUrl(URL.createObjectURL(blob));
        setRecordingBlob(blob);
      };
      mediaRecorder.start();
      setIsRecording(true);
      setRecordingTime(0);
      timerRef.current = window.setInterval(() => setRecordingTime(prev => prev + 1), 1000);
    } catch (err: any) {
      if (err.name !== 'NotAllowedError') setError("Permission required to record screen.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      if (timerRef.current) { window.clearInterval(timerRef.current); timerRef.current = null; }
      if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
    }
  };

  const handleTranscribeMeeting = async () => {
    if (!recordingBlob) return;
    setIsLoading(true);
    setError(null);
    try {
      const base64 = await blobToBase64(recordingBlob);
      const result = await transcribeAudio(base64, 'video/webm');
      setTranscript(result);
    } catch (err: any) {
      setError("Analysis Error: " + err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="max-w-screen-2xl mx-auto space-y-16 animate-fade-in">
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-16">
        <div className="lg:col-span-4 space-y-10">
          <div className="card-premium p-12 rounded-[3rem] shadow-2xl">
            <h3 className="text-sm font-black text-gray-400 uppercase tracking-widest mb-10 flex items-center gap-4">
              <Video size={28} className="text-primary-900" />
              {t.labels.recordingDock}
            </h3>
            {!isRecording && !videoUrl && (
              <div className="space-y-8">
                <div className="p-8 bg-primary-50 rounded-3xl border border-primary-100 text-primary-900 text-base font-medium leading-relaxed">
                  {t.labels.meetingTip}
                </div>
                <button 
                  onClick={startRecording} 
                  className="w-full h-20 rounded-3xl bg-primary-900 text-white font-black text-lg uppercase shadow-2xl shadow-primary-900/10 flex items-center justify-center gap-4 hover:bg-primary-800 transition-all active:scale-95"
                >
                  <MonitorPlay size={28} />
                  <span>{t.labels.startBtn.toUpperCase()}</span>
                </button>
              </div>
            )}
            {isRecording && (
              <div className="text-center space-y-10 animate-pulse">
                <div className="text-7xl font-black text-red-700 tracking-tighter font-mono drop-shadow-lg">{formatTime(recordingTime)}</div>
                <button 
                  onClick={stopRecording} 
                  className="w-full h-20 rounded-3xl bg-red-700 text-white font-black text-lg uppercase flex items-center justify-center gap-4 hover:bg-red-800 transition-all shadow-2xl shadow-red-200"
                >
                  <Square size={24} />
                  <span>{t.labels.stopSave}</span>
                </button>
              </div>
            )}
            {videoUrl && !isRecording && (
              <div className="space-y-6">
                <button onClick={() => { setVideoUrl(null); setTranscript(''); }} className="w-full h-16 rounded-2xl font-black text-sm uppercase text-gray-400 hover:text-primary-900 transition-colors border border-transparent hover:border-primary-100">
                  {t.labels.reRecord}
                </button>
                <a href={videoUrl} download="VPTX_Meeting.webm" className="flex items-center justify-center gap-4 w-full h-20 bg-gray-900 text-white rounded-[2rem] font-black text-lg uppercase shadow-2xl hover:bg-black transition-all">
                  <Download size={28} /> 
                  <span>{t.labels.downloadVideo}</span>
                </a>
              </div>
            )}
          </div>
          {videoUrl && !isRecording && (
            <div className="card-premium p-12 rounded-[3rem] text-center space-y-8 shadow-2xl">
               <div className="w-20 h-20 bg-primary-50 rounded-full flex items-center justify-center mx-auto text-primary-900 border border-primary-100"><Sparkles size={40} /></div>
               <div className="space-y-4">
                  <h4 className="font-black text-gray-900 uppercase text-sm tracking-widest">GEMINI AI ANALYTICS</h4>
                  <p className="text-base text-gray-500 font-medium leading-relaxed px-6 opacity-80">AI Gemini will process the audio and create an automated summary for you.</p>
               </div>
               <button 
                 onClick={handleTranscribeMeeting} 
                 disabled={isLoading} 
                 className={`w-full h-16 rounded-2xl font-black text-sm uppercase shadow-2xl flex items-center justify-center gap-4 transition-all ${
                   isLoading ? 'bg-gray-200 text-gray-400' : 'bg-primary-900 text-white hover:bg-primary-800 shadow-primary-900/10 active:scale-95'
                 }`}
               >
                  {isLoading ? <div className="w-6 h-6 border-4 border-white/20 border-t-white rounded-full animate-spin"></div> : <Wand2 size={24} />}
                  <span>{t.labels.analyzeMeeting}</span>
               </button>
            </div>
          )}
        </div>

        <div className="lg:col-span-8 space-y-12">
          {videoUrl ? (
            <div className="bg-black rounded-[3.5rem] overflow-hidden shadow-2xl border-4 border-white/20 aspect-video ring-4 ring-black/10">
              <video src={videoUrl} controls className="w-full h-full" />
            </div>
          ) : (
            <div className="bg-white/40 border-4 border-dashed border-gray-200/50 rounded-[3.5rem] h-[600px] flex flex-col items-center justify-center text-white backdrop-blur-md">
              <MonitorPlay size={100} className="mb-8 opacity-20" />
              <p className="font-black text-lg uppercase tracking-[0.5em] opacity-40 italic">{t.labels.recordingWait}</p>
            </div>
          )}

          {transcript && (
            <div className="bg-white rounded-[3rem] shadow-2xl border border-gray-100 overflow-hidden animate-slide-up">
              <div className="bg-gray-50 px-12 py-10 border-b border-gray-200 flex justify-between items-center">
                <h3 className="font-black text-gray-900 uppercase text-sm tracking-widest flex items-center gap-4">
                   <FileText size={24} className="text-primary-900" /> {t.labels.transcriptionResult}
                </h3>
                <button 
                  onClick={() => { navigator.clipboard.writeText(transcript); setCopied(true); setTimeout(() => setCopied(false), 2000); }} 
                  className="text-primary-900 font-black text-sm hover:underline uppercase tracking-widest flex items-center gap-2"
                >
                  {copied ? <Check size={18} /> : <Copy size={18} />}
                  <span>{copied ? 'COPIED' : t.labels.copyBtn.toUpperCase()}</span>
                </button>
              </div>
              <div className="p-12">
                <div className="text-gray-900 text-2xl font-medium leading-relaxed whitespace-pre-wrap max-h-[700px] overflow-y-auto custom-scrollbar">{transcript}</div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default ScreenRecorder;

import React, { useState } from 'react';
import { Upload, FileText, FileSpreadsheet, Presentation, Check, Download, AlertCircle, FileType, CheckCircle } from 'lucide-react';
import Button from './Button';
import { analyzeDocument } from '../services/geminiService';
import { blobToBase64 } from '../utils/audioUtils';
import { UILang, TRANSLATIONS } from '../types';

type TargetFormat = 'word' | 'excel' | 'ppt';
interface Props { lang: UILang }

const FileConverter: React.FC<Props> = ({ lang }) => {
  const [file, setFile] = useState<File | null>(null);
  const [targetFormat, setTargetFormat] = useState<TargetFormat>('word');
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<string>('');
  const [error, setError] = useState<string | null>(null);

  const t = TRANSLATIONS[lang];

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
      setResult('');
      setError(null);
    }
  };

  const handleConvert = async () => {
    if (!file) return;
    setIsLoading(true);
    setError(null);
    setResult('');
    try {
      const base64 = await blobToBase64(file);
      const convertedText = await analyzeDocument(base64, file.type, targetFormat);
      setResult(convertedText);
    } catch (err: any) {
      setError(err.message || "Conversion failed.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleDownload = () => {
    if (!result) return;
    let mimeType = 'text/plain';
    let extension = 'txt';
    let content = result;

    if (targetFormat === 'excel') {
      mimeType = 'application/vnd.ms-excel';
      extension = 'xls';
      content = `<html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:x="urn:schemas-microsoft-com:office:excel" xmlns="http://www.w3.org/TR/REC-html40"><head><meta http-equiv="Content-Type" content="text/html; charset=utf-8"></head><body>${result}</body></html>`;
    } else if (targetFormat === 'word') {
      mimeType = 'application/msword';
      extension = 'doc';
      content = `<html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'><head><meta charset='utf-8'></head><body>${result}</body></html>`;
    }

    const blob = new Blob([content], { type: mimeType });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `VPTX_AI_Converted_${Date.now()}.${extension}`;
    link.click();
  };

  return (
    <div className="max-w-screen-xl mx-auto space-y-16 animate-fade-in">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-16">
        <div className="card-premium p-12 rounded-[3.5rem] flex flex-col shadow-2xl">
          <h3 className="text-xl font-black text-gray-900 mb-12 flex items-center gap-5 uppercase tracking-tighter">
            <div className="w-16 h-16 rounded-2xl bg-primary-50 flex items-center justify-center text-primary-900 shadow-inner border border-primary-100">
              <Upload size={32} />
            </div>
            {t.labels.convStep1}
          </h3>
          <div className="relative flex-grow">
            <input type="file" accept="image/*,application/pdf" onChange={handleFileChange} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10" />
            <div className={`border-2 border-dashed rounded-[3rem] p-12 text-center transition-all h-full flex flex-col items-center justify-center min-h-[400px] ${file ? 'border-primary-900 bg-primary-50/20 shadow-inner' : 'border-gray-200 hover:border-primary-200 hover:bg-primary-50/10'}`}>
              {file ? (
                 <div className="text-primary-900 flex flex-col items-center animate-fade-in">
                   <FileType size={100} className="mb-6 text-primary-900 drop-shadow-sm" />
                   <span className="truncate max-w-[280px] font-black text-xl">{file.name}</span>
                   <span className="text-xs uppercase font-bold text-gray-400 mt-3">{(file.size / 1024 / 1024).toFixed(2)} MB</span>
                 </div>
              ) : (
                <div className="space-y-6">
                  <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center mx-auto mb-6 border border-gray-100"><Upload size={32} className="text-gray-300" /></div>
                  <p className="text-lg text-gray-400 font-black uppercase tracking-widest">{t.labels.uploadArea}</p>
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="card-premium p-12 rounded-[3.5rem] flex flex-col shadow-2xl">
          <h3 className="text-xl font-black text-gray-900 mb-12 flex items-center gap-5 uppercase tracking-tighter">
            <div className="w-16 h-16 rounded-2xl bg-primary-50 flex items-center justify-center text-primary-900 shadow-inner border border-primary-100">
              <FileType size={32} />
            </div>
            {t.labels.convStep2}
          </h3>
          <div className="space-y-6 flex-grow">
            {[
              { id: 'word', icon: <FileText size={32} />, label: 'Microsoft Word', desc: 'Preserve tables & layout', color: 'blue' },
              { id: 'excel', icon: <FileSpreadsheet size={32} />, label: 'Microsoft Excel', desc: 'Extract data grid', color: 'emerald' },
              { id: 'ppt', icon: <Presentation size={32} />, label: 'PowerPoint Outline', desc: 'Generate slide deck ideas', color: 'orange' }
            ].map((f) => (
              <button
                key={f.id}
                onClick={() => setTargetFormat(f.id as TargetFormat)}
                className={`w-full p-8 rounded-[2rem] border-2 flex items-center gap-8 transition-all duration-300 ${
                  targetFormat === f.id ? 'border-primary-900 bg-primary-50 shadow-xl scale-105' : 'border-gray-50 hover:bg-gray-50'
                }`}
              >
                <div className="p-5 rounded-2xl bg-white shadow-md border border-gray-100 text-primary-900">{f.icon}</div>
                <div className="text-left">
                  <div className="font-black text-gray-900 text-2xl">{f.label}</div>
                  <div className="text-xs text-gray-400 font-bold uppercase tracking-widest">{f.desc}</div>
                </div>
                {targetFormat === f.id && <Check size={32} className="ml-auto text-primary-900" />}
              </button>
            ))}
          </div>
          <button 
            onClick={handleConvert} 
            disabled={!file || isLoading} 
            className={`mt-12 h-20 w-full rounded-3xl font-black text-xl shadow-2xl transition-all flex items-center justify-center gap-4 ${
              !file || isLoading ? 'bg-gray-200 text-gray-400 cursor-not-allowed' : 'bg-primary-900 text-white hover:bg-primary-800 shadow-primary-900/20 active:scale-95'
            }`}
          >
            {isLoading ? <div className="w-8 h-8 border-4 border-white/20 border-t-white rounded-full animate-spin"></div> : null}
