import React, { useState, useEffect, useMemo } from 'react';
import { Download, Sparkles, AlertCircle, Quote, Info, Headphones, Check } from 'lucide-react';
import { VOICE_OPTIONS, LANGUAGES, UILang, TRANSLATIONS } from '../types';
import { generateSpeech } from '../services/geminiService';

interface Props { lang: UILang }

const TextToAudio: React.FC<Props> = ({ lang }) => {
  const [text, setText] = useState('');
  const [selectedLanguage, setSelectedLanguage] = useState('vi');
  const [selectedVoice, setSelectedVoice] = useState('Puck');
  const [isLoading, setIsLoading] = useState(false);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const t = TRANSLATIONS[lang];

  useEffect(() => {
    return () => { if (audioUrl) URL.revokeObjectURL(audioUrl); };
  }, [audioUrl]);

  const filteredVoices = useMemo(() => {
    return VOICE_OPTIONS.filter(v => v.languages.includes(selectedLanguage));
  }, [selectedLanguage]);

  useEffect(() => {
    const recommended = filteredVoices.find(v => v.recommendedFor.includes(selectedLanguage)) || filteredVoices[0];
    if (recommended) setSelectedVoice(recommended.name);
  }, [selectedLanguage, filteredVoices]);

  const handleGenerate = async () => {
    if (!text.trim()) return;
    setIsLoading(true);
    setError(null);
    setAudioUrl(null);
    try {
      const url = await generateSpeech(text, selectedVoice);
      setAudioUrl(url);
    } catch (err: any) {
      setError(err.message || "Failed to generate audio.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="max-w-screen-2xl mx-auto space-y-16 animate-fade-in">
      <div className="grid grid-cols-1 xl:grid-cols-12 gap-16 items-start">

        {/* Editor Area */}
        <div className="xl:col-span-8 space-y-10">
          <div className="card-premium rounded-[3rem] overflow-hidden shadow-2xl">
            <div className="border-b border-gray-100 p-10 flex flex-wrap justify-between items-center gap-8 bg-gray-50/50">
              <label className="flex items-center gap-4 text-sm font-black text-gray-600 uppercase tracking-widest">
                <Quote size={24} className="text-primary-900" />
                {t.labels.textContent}
              </label>
              <div className="flex bg-gray-200/50 p-2 rounded-2xl border border-gray-200">
                {LANGUAGES.map(l => (
                  <button
                    key={l.id}
                    onClick={() => setSelectedLanguage(l.id)}
                    className={`px-6 py-3 rounded-xl text-sm font-black transition-all ${
                      selectedLanguage === l.id 
                        ? 'bg-primary-900 text-white shadow-lg scale-105' 
                        : 'text-gray-500 hover:text-primary-900'
                    }`}
                  >
                    {l.flag} {l.label}
                  </button>
                ))}
              </div>
            </div>

            <textarea
              value={text}
              onChange={(e) => setText(e.target.value)}
              placeholder={t.labels.placeholderTTS}
              className="w-full h-[520px] p-12 text-gray-900 border-0 focus:ring-0 resize-none text-2xl md:text-3xl font-medium leading-relaxed bg-white placeholder-gray-300 custom-scrollbar"
            />

            <div className="p-10 bg-gray-50 border-t border-gray-100 flex items-center justify-between">
              <div className="flex items-center gap-4 text-xs text-gray-400 font-bold uppercase tracking-widest">
                <Info size={24} className="text-primary-400" />
                Gemini AI Voice Engine
              </div>
              <button 
                onClick={handleGenerate} 
                disabled={!text.trim() || isLoading} 
                className={`px-16 h-20 rounded-3xl text-xl font-black transition-all shadow-2xl flex items-center gap-4 ${
                  !text.trim() || isLoading 
                    ? 'bg-gray-200 text-gray-400 cursor-not-allowed shadow-none' 
                    : 'bg-primary-900 text-white hover:bg-primary-800 shadow-primary-900/20 active:scale-95'
                }`}
              >
                {isLoading ? (
                  <div className="w-8 h-8 border-4 border-white/20 border-t-white rounded-full animate-spin"></div>
                ) : (
                  <Sparkles size={28} />
                )}
                <span>{t.labels.startBtn.toUpperCase()}</span>
              </button>
            </div>
          </div>
          {error && (
            <div className="bg-red-50 text-red-700 p-8 rounded-3xl flex items-center gap-6 border border-red-100 animate-fade-in">
              <AlertCircle size={32} />
              <p className="text-lg font-black uppercase">{error}</p>
            </div>
          )}
        </div>

        {/* Options Area */}
        <div className="xl:col-span-4 space-y-10">
          <div className="card-premium p-12 rounded-[3rem] shadow-2xl">
            <h3 className="text-sm font-black text-gray-400 uppercase tracking-widest mb-10 flex items-center gap-4">
              <Headphones size={28} className="text-primary-900" />
              {t.labels.voiceOptions}
            </h3>

            <div className="space-y-6 max-h-[460px] overflow-y-auto pr-4 custom-scrollbar">
              {filteredVoices.map((voice) => {
                const isActive = selectedVoice === voice.name;
                const description = t.voiceDescriptions[voice.name];
                return (
                  <button
                    key={voice.name}
                    onClick={() => setSelectedVoice(voice.name)}
                    className={`w-full group p-8 rounded-[2rem] border-2 text-left transition-all ${
                      isActive 
                        ? 'border-primary-900 bg-primary-50 shadow-xl scale-105' 
                        : 'border-gray-50 hover:bg-gray-50'
                    }`}
                  >
                    <div className="flex justify-between items-center mb-4">
                      <div className="flex items-center gap-3">
                        <span className={`font-black text-xl ${isActive ? 'text-primary-900' : 'text-gray-900'}`}>{voice.name}</span>
                        {isActive && <Check size={20} className="text-primary-900" />}
                      </div>
                      <span className={`text-xs font-black px-4 py-1.5 rounded-full ${voice.gender === 'Nam' ? 'bg-blue-100 text-blue-700' : 'bg-pink-100 text-pink-700'}`}>
                        {voice.gender === 'Nam' ? t.labels.male : t.labels.female}
                      </span>
                    </div>
                    <p className="text-sm text-gray-500 leading-relaxed italic font-medium">{description}</p>
                  </button>
                );
              })}
            </div>
          </div>

          {audioUrl && (
            <div className="bg-primary-900 text-white p-12 rounded-[3rem] shadow-2xl animate-fade-in ring-4 ring-white/10">
              <h3 className="text-xs font-black text-primary-200 uppercase tracking-widest mb-10">{t.labels.audioOutput}</h3>
              <div className="space-y-10">
                <audio controls src={audioUrl} className="w-full h-14 invert brightness-150" autoPlay />
                <a 
                  href={audioUrl} 
                  download={`VPTX-AI-Audio-${Date.now()}.wav`} 
                  className="flex items-center justify-center gap-4 w-full py-6 bg-white text-primary-900 rounded-[2rem] text-lg font-black hover:scale-105 active:scale-95 transition-all shadow-2xl shadow-black/20"
                >
                  <Download size={28} />
                  <span>{t.labels.downloadBtn.toUpperCase()} (WAV)</span>
                </a>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default TextToAudio;

